const categoriaIndex = diasPassados % 6;
const categoria = categorias[categoriaIndex];
const numeroArtigo = ARTIGO_INICIAL + diasPassados;

// Data formatada em português
const meses = ['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
const dataFormatada = `${agoraBrasilia.getDate()} de ${meses[agoraBrasilia.getMonth()]} de ${agoraBrasilia.getFullYear()}`;
const ano = agoraBrasilia.getFullYear();
const mes = String(agoraBrasilia.getMonth() + 1).padStart(2, '0');
const dia = String(agoraBrasilia.getDate()).padStart(2, '0');
const dataISO = `${ano}-${mes}-${dia}`;

return [{
  json: {
    categoria,
    numeroArtigo,
    dataFormatada,
    dataISO,
    nomeArquivo: `artigo-${numeroArtigo}.html`
