let artigo;
try {
  // Limpar possível markdown
  const jsonLimpo = respostaGPT.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  artigo = JSON.parse(jsonLimpo);
} catch(e) {
  // Tentar extrair JSON se veio com texto ao redor
  const match = respostaGPT.match(/\{[\s\S]*\}/);
  if (match) {
    artigo = JSON.parse(match[0]);
  } else {
    throw new Error('GPT não retornou JSON válido: ' + respostaGPT.substring(0, 200));
  }
}

