    artigo,
    nomeArquivo
  },
  binary: {
    artigoHtml: {
      data: base64,
      mimeType: 'text/html',
      fileName: nomeArquivo
    }
  }
}];

// Ler blog.js atual
const binaryData = $input.first().binary.blogJs;
const blogJsAtual = Buffer.from(binaryData.data, 'base64').toString('utf-8');

// Dados do artigo gerado
const dadosArtigo = $('Montar HTML do Artigo').first().json;
const { categoria, numeroArtigo, dataISO, artigo, nomeArquivo } = dadosArtigo;

// Encontrar o maior ID existente no blog.js
const idMatches = [...blogJsAtual.matchAll(/id:\s*(\d+)/g)];
const maiorId = idMatches.length > 0 ? Math.max(...idMatches.map(m => parseInt(m[1]))) : 100;
const novoId = maiorId + 1;

// Montar nova entrada para o blog.js
const novaEntrada = `    {
        id: ${novoId},
        title: ${JSON.stringify(artigo.titulo)},
        category: ${JSON.stringify(categoria.id)},
        categoryLabel: ${JSON.stringify(categoria.label)},
        excerpt: ${JSON.stringify(artigo.excerpt)},
        content: ${JSON.stringify(artigo.excerpt)},
        author: "Dr. Rafael Fratazzi",
        date: "${dataISO}",
        readTime: "${artigo.tempoLeitura}",
        image: "${categoria.emoji}",
        tags: ${JSON.stringify(artigo.tags)},
        link: "artigos/${nomeArquivo}"
    }`;

// Inserir nova entrada no início do array blogPosts
const blogJsAtualizado = blogJsAtual.replace(
  'const blogPosts = [',
  `const blogPosts = [\n${novaEntrada},`
);

// Preparar como binário para upload
const base64 = Buffer.from(blogJsAtualizado, 'utf-8').toString('base64');

return [{
  json: { novoId, nomeArquivo, titulo: artigo.titulo },
  binary: {
    blogJs: {
      data: base64,
      mimeType: 'application/javascript',
      fileName: 'blog.js'
    }
  }
}];

